  ('dietitian-moex-08905', 'dietitian', 'dietitian-moex-098-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '依據食品業者良好衛生規範規定，蓄水池應保持清潔，其設置地點應距污穢場所、化糞池等污染源保持 多少之距離？', '["3公尺以上", "5公尺以上", "10公尺以上", "15公尺以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "e8ef415595ad", "answer_pdf_sha1": "d0184ce20793", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08906', 'dietitian', 'dietitian-moex-098-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '依行政院衛生署食品衛生標準中，有關餐具之衛生，下列何者錯誤？', '["餐具中大腸桿菌群應為陰性", "餐具不得殘留油脂、澱粉", "以三槽式洗滌法清洗餐具，其第一槽之水溫應維持在43~49℃間", "以三槽式洗滌法清洗餐具，其第三槽為消毒作業"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "e8ef415595ad", "answer_pdf_sha1": "d0184ce20793", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08907', 'dietitian', 'dietitian-moex-098-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關容器或包裝的食品及食品添加物之標示，下列敘述何者錯誤？', '["最大表面積大於10平方公分，所有字體之長度及寬度不得小於2 mm", "最大表面積小於10平方公分之小包裝，其品名、有效日期等標示之字體的長度及寬度得小於2 mm", "最大表面積小於10平方公分之小包裝，標示廠商名稱時所用字體之長度及寬度不得小於2 mm", "在國內製造者其標示如兼用外文，應以中文為主、外文為輔"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "e8ef415595ad", "answer_pdf_sha1": "d0184ce20793", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08908', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '自97年1月1日起，「市售包裝食品營養標示規範」規定食品之營養標示之標題包括熱量、蛋白質、碳 水化合物、鈉、反式脂肪和下列何種營養素？', '["不飽和脂肪（unsaturated fat）", "單元不飽和脂肪酸（monounsaturated fatty acids）", "飽和脂肪（saturated fat）", "氫化脂肪酸（hydrogenated fatty acids）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "c90dd73f29c5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08909', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '今有一位3歲兒童的BMI值高於該年齡與性別的肥胖BMI值，請問依據「兒童與青少年肥胖定義及處理 原則」，該以下列那一個步驟再進行篩選或處理？', '["隔年再評估即可", "維持體重不再上升就可", "必須立即執行體重控制計畫", "需進一步評估血壓、血脂值和肥胖家族史"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "c90dd73f29c5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08910', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '民國91年行政院衛生署邀集學者專家將「每日營養素建議攝取量」修訂為「國人膳食營養素參考攝取 量」，此修訂版中增加「上限攝取量」（tolerable upper intake levels）的建議，上限攝取量之評估必須 包括風險評估模式（risk assessment），風險評估模式中就危害發生率與嚴重程度分析營養素攝取量與 危害指標之間的關係稱為：', '["危害評估（hazard assessment）", "曝露評估（exposure assessment）", "劑量效應評估（dose-response assessment）", "風險界定（risk characterization）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "c90dd73f29c5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08911', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '社區營養計畫執行策略行銷過程（strategic marketing process）首要步驟為：', '["定義問題（problem definition）", "設定目標（goal setting）", "研究並分析消費者（consumer research and analysis）", "行動計畫與經費預算（action plan and budget）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "c90dd73f29c5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08912', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列對於「健康盒餐」的敘述，何者正確？', '["每個健康盒餐的熱量建議量為700大卡", "每個健康盒餐的蔬菜類建議量為1.5份", "市售盒餐的肉魚豆蛋類份量合於規範", "幾乎所有市售盒餐的五穀根莖類份量與建議量相符"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "c90dd73f29c5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
